function ForgotScreen({ nav, user, setUser }) {
  const [step, setStep] = useState(0);
  const [code, setCode] = useState(["", "", "", "", ""]);
  const [resetEmail, setResetEmail] = useState(user ? user.email : "");
  const [newPw, setNewPw] = useState("");
  const [confirmPw, setConfirmPw] = useState("");
  const [pwErr, setPwErr] = useState("");

  const handleReset = () => {
    if (newPw.length < 4) { setPwErr("Password must be at least 4 characters."); return; }
    if (newPw !== confirmPw) { setPwErr("Passwords do not match."); return; }
    setPwErr("");
    if (user) setUser({ ...user, pass: newPw });
    setStep(3);
  };

  if (step === 0) return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: C.bg }}>
      <StatusBar /><div style={{ padding: "8px 20px" }}><button onClick={() => nav("signin")} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}><IcBack /></button></div>
      <div style={{ flex: 1, padding: "0 28px" }}>
        <div style={{ marginTop: 40, marginBottom: 30 }}><Heading size={30}>Forgot Password</Heading></div>
        <p style={{ fontSize: 14, color: C.gray, margin: "0 0 24px", fontFamily: FNT, lineHeight: 1.5 }}>Please enter the email address associated with your account.</p>
        <FormInput label="Email" icon={<IcMail />} placeholder="your@email.com" value={resetEmail} onChange={setResetEmail} />
        <div style={{ marginTop: 24 }}><OliveBtn onClick={() => setStep(1)} disabled={!resetEmail.trim()}>Send Code</OliveBtn></div>
      </div>
    </div>
  );

  if (step === 1) return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: C.bg }}>
      <StatusBar /><div style={{ padding: "8px 20px" }}><button onClick={() => setStep(0)} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}><IcBack /></button></div>
      <div style={{ flex: 1, padding: "0 28px" }}>
        <div style={{ marginTop: 40, marginBottom: 24 }}><Heading size={30}>Check your email</Heading></div>
        <p style={{ fontSize: 14, color: C.gray, margin: "0 0 4px", fontFamily: FNT }}>We sent a reset link to <strong style={{ color: C.olive }}>{resetEmail}</strong></p>
        <p style={{ fontSize: 14, color: C.dark, margin: "0 0 24px", fontFamily: FNT }}>enter the 5 digit code mentioned in the email</p>
        <div style={{ display: "flex", gap: 10, marginBottom: 24 }}>
          {code.map((c, i) => (
            <input key={i} maxLength={1} value={c} onChange={e => { const n = [...code]; n[i] = e.target.value; setCode(n); if (e.target.value && i < 4) { const next = e.target.nextElementSibling; if (next) next.focus(); } }} style={{ width: 56, height: 64, textAlign: "center", fontSize: 24, fontWeight: 600, borderRadius: 14, border: `1.5px solid ${c ? C.olive : C.grayLighter}`, outline: "none", background: C.bg, fontFamily: FNT }} />
          ))}
        </div>
        <OliveBtn onClick={() => setStep(2)}>Verify Code</OliveBtn>
        <div style={{ textAlign: "center", marginTop: 16 }}>
          <span style={{ fontSize: 14, color: C.gray, fontFamily: FNT }}>{"Didn\u0027t receive the email? "}</span>
          <button style={{ background: "none", border: "none", color: C.olive, fontSize: 14, fontWeight: 600, cursor: "pointer", fontFamily: FNT }}>Resend</button>
        </div>
      </div>
    </div>
  );

  if (step === 2) return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: C.bg }}>
      <StatusBar /><div style={{ padding: "8px 20px" }}><button onClick={() => setStep(1)} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}><IcBack /></button></div>
      <div style={{ flex: 1, padding: "0 28px" }}>
        <div style={{ marginTop: 40, marginBottom: 30 }}><Heading size={30}>New password</Heading></div>
        <FormInput label="New password" icon={<IcLock />} placeholder="Create a new password" value={newPw} onChange={setNewPw} showToggle />
        <FormInput label="Confirm password" icon={<IcLock />} placeholder="Re-enter your password" value={confirmPw} onChange={setConfirmPw} showToggle />
        {pwErr && <p style={{ color: "#c0392b", fontSize: 13, marginBottom: 12, fontFamily: FNT }}>\u26a0 {pwErr}</p>}
        <OliveBtn onClick={handleReset} disabled={!newPw || !confirmPw}>Reset password</OliveBtn>
      </div>
    </div>
  );

  return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", background: C.bg, gap: 16, padding: "0 32px" }}>
      <div style={{ width: 72, height: 72, borderRadius: 36, background: C.oliveLight, display: "flex", alignItems: "center", justifyContent: "center" }}><IcChk /></div>
      <h2 style={{ fontSize: 24, fontWeight: 700, color: C.dark, margin: 0, fontFamily: FNT }}>Password reset!</h2>
      <p style={{ fontSize: 13, color: C.gray, textAlign: "center", fontFamily: FNT }}>Your new password is saved. You can now sign in.</p>
      <OliveBtn onClick={() => nav("signin")} full={false}>Back to sign in</OliveBtn>
    </div>
  );
}

function QuizScreen({ nav }) {
  const [step, setStep] = useState(0);
  const [answers, setAnswers] = useState({});
  const [tried, setTried] = useState(false);

  const handleBack = () => {
    setTried(false);
    if (step === 0) nav("signup");
    else setStep(s => s - 1);
  };

  if (step >= QUIZ.length) return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", background: C.bg, gap: 16, padding: "0 32px" }}>
      <div style={{ fontSize: 56 }}>🎉</div>
      <h2 style={{ fontSize: 24, fontWeight: 700, color: C.dark, margin: 0, fontFamily: FNT }}>{"You\u0027re all set!"}</h2>
      <p style={{ fontSize: 14, color: C.gray, textAlign: "center", fontFamily: FNT }}>Your preferences are saved.</p>
      <OliveBtn onClick={() => nav("home")} full={false}>Explore nooks</OliveBtn>
    </div>
  );

  const q = QUIZ[step];
  const maxSel = q.max || undefined;
  const cur = answers[step] || (q.multi ? [] : "");
  const select = (opt) => {
    if (q.multi) {
      const arr = Array.isArray(cur) ? cur : [];
      if (arr.includes(opt)) {
        setAnswers(prev => ({ ...prev, [step]: arr.filter(x => x !== opt) }));
      } else {
        if (maxSel && arr.length >= maxSel) return;
        setAnswers(prev => ({ ...prev, [step]: [...arr, opt] }));
      }
    } else {
      setAnswers(prev => ({ ...prev, [step]: opt }));
    }
  };
  const ok = q.multi ? (Array.isArray(cur) && cur.length > 0) : !!cur;
  const pct = ((step + 1) / QUIZ.length) * 100;
  const handleNext = () => {
    if (!ok) { setTried(true); return; }
    setTried(false);
    setStep(s => s + 1);
  };

  return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: C.bg }}>
      <StatusBar />
      <div style={{ padding: "8px 20px 0", display: "flex", alignItems: "center", gap: 10 }}>
        <button onClick={handleBack} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}><IcBack /></button>
        <span style={{ fontSize: 13, color: C.grayLight, fontFamily: FNT }}>{step + 1} of {QUIZ.length}</span>
      </div>
      <div style={{ padding: "8px 28px 0" }}>
        <div style={{ height: 6, borderRadius: 3, background: C.oliveLight, marginBottom: 20 }}>
          <div style={{ height: 6, borderRadius: 3, background: C.dark, width: `${pct}%`, transition: "width 0.3s" }} />
        </div>
        <h2 style={{ fontSize: 24, fontWeight: 700, color: C.dark, margin: "0 0 4px", fontFamily: FNT }}>{q.title}</h2>
        <p style={{ fontSize: 14, color: C.grayLight, margin: "0 0 20px", fontFamily: FNT }}>{q.sub}</p>
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: "0 28px 16px" }}>
        {q.opts.map(opt => {
          const sel = q.multi ? (Array.isArray(cur) && cur.includes(opt)) : cur === opt;
          const atMax = q.multi && maxSel && !sel && Array.isArray(cur) && cur.length >= maxSel;
          return (
            <button key={opt} onClick={() => select(opt)} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", width: "100%", padding: "16px 18px", marginBottom: 10, borderRadius: 14, border: `1.5px solid ${sel ? C.olive : C.grayLighter}`, background: sel ? C.oliveLight : C.bg, cursor: atMax ? "not-allowed" : "pointer", transition: "all 0.2s", fontFamily: FNT, opacity: atMax ? 0.5 : 1 }}>
              <span style={{ fontSize: 15, fontWeight: sel ? 600 : 400, color: C.dark }}>{opt}</span>
              {sel && <IcChk />}
            </button>
          );
        })}
      </div>
      <div style={{ padding: "12px 28px 32px" }}>
        <OliveBtn onClick={handleNext} disabled={!ok}>{step === QUIZ.length - 1 ? "Finish" : "Next"}</OliveBtn>
        {tried && !ok && <p style={{ color: "#c0392b", fontSize: 13, textAlign: "center", marginTop: 8, fontFamily: FNT }}>⚠ Please select at least one {q.multi ? "option" : "choice"}</p>}
        {q.multi && maxSel && <p style={{ fontSize: 12, color: C.grayLight, textAlign: "center", marginTop: 4, fontFamily: FNT }}>{Array.isArray(cur) ? cur.length : 0}/{maxSel} selected</p>}
      </div>
    </div>
  );
}

