function RadioScale({ label, leftLabel, rightLabel, value, onChange }) {
  return (
    <div style={{ marginBottom: 18 }}>
      <label style={{ fontSize: 15, fontWeight: 600, color: C.dark, display: "block", marginBottom: 8, fontFamily: FNT }}>{label}</label>
      <div style={{ display: "flex", gap: 16, alignItems: "center", justifyContent: "center" }}>
        {[1, 2, 3, 4, 5].map(i => (
          <button key={i} onClick={() => onChange(value === i ? 0 : i)} style={{ width: 32, height: 32, borderRadius: 16, border: `2.5px solid ${C.dark}`, background: value >= i ? C.dark : "transparent", cursor: "pointer", transition: "all 0.15s" }} />
        ))}
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
        <span style={{ fontSize: 12, color: C.dark, fontFamily: FNT }}>{leftLabel}</span>
        <span style={{ fontSize: 12, color: C.dark, fontFamily: FNT }}>{rightLabel}</span>
      </div>
    </div>
  );
}

function WriteReviewScreen({ nav, pid, userReviews, setUserReviews }) {
  const p = PLACES.find(x => x.id === pid) || PLACES[0];
  const existing = userReviews[pid];
  const [rating, setRating] = useState(existing ? existing.rating : 0);
  const [noise, setNoise] = useState(existing ? existing.noise : 0);
  const [crowd, setCrowd] = useState(existing ? existing.crowd : 0);
  const [seating, setSeating] = useState(existing ? existing.seating : 0);
  const [wifi, setWifi] = useState(existing ? existing.wifi : 0);
  const [text, setText] = useState(existing ? existing.text : "");
  const [done, setDone] = useState(false);
  const [selTags, setSelTags] = useState(new Set(existing ? existing.tags || [] : []));
  const isPhysical = p.tags.some(t => ["Physical", "Active", "Craft", "Creative"].includes(t));
  const availTags = isPhysical
    ? ["Loud", "Quiet", "Social", "Beginner-friendly", "Well-equipped", "Good vibes", "Clean", "Spacious", "Affordable"]
    : ["Quiet", "Loud", "Wi-Fi", "Outlets", "Social", "Good coffee", "Natural light", "Comfortable seating", "Late hours", "Spacious"];
  const tagToggle = t => { const n = new Set(selTags); n.has(t) ? n.delete(t) : n.add(t); setSelTags(n); };

  if (done) return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: C.bg }}>
      <StatusBar />
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 16, padding: "0 32px" }}>
        <svg width="100" height="100" viewBox="0 0 100 100" fill="none"><path d="M20 55L40 75L80 25" stroke={C.dark} strokeWidth="8" strokeLinecap="round" strokeLinejoin="round" /></svg>
        <h2 style={{ fontSize: 26, fontWeight: 700, color: C.dark, margin: 0, fontFamily: FNT, textAlign: "center" }}>{existing ? "Review updated!" : "Review submitted!"}</h2>
        <p style={{ fontSize: 15, color: C.dark, textAlign: "center", fontFamily: FNT, lineHeight: 1.5 }}>Thank you for sharing. This helps everyone find great places.</p>
        <OutlineBtn onClick={() => nav("place", pid)}>Back</OutlineBtn>
      </div>
      <BottomTabs active="home" onNav={nav} />
    </div>
  );

  return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: C.bg }}>
      <StatusBar />
      <div style={{ flex: 1, overflowY: "auto", padding: "0 24px 90px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0 0", marginBottom: 16 }}>
          <button onClick={() => nav("place", pid)} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}><IcBack /></button>
          <h2 style={{ fontSize: 22, fontWeight: 700, color: C.dark, margin: 0, fontFamily: FNT }}>{existing ? "Edit your review" : "Add review"} for {p.name}</h2>
        </div>
        <div style={{ marginBottom: 20 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <span style={{ fontSize: 15, fontWeight: 700, color: C.dark, fontFamily: FNT }}>Overall Rating:</span>
            <Stars rating={rating} onRate={v => setRating(v === rating ? 0 : v)} size={28} />
          </div>
        </div>
        <h3 style={{ fontSize: 16, fontWeight: 700, color: C.dark, margin: "0 0 12px", fontFamily: FNT, textDecoration: "underline" }}>Rate the following:</h3>
        <RadioScale label="Noise:" leftLabel="Silent" rightLabel="Very loud" value={noise} onChange={setNoise} />
        <RadioScale label="Crowded level:" leftLabel="Empty" rightLabel="Very crowded" value={crowd} onChange={setCrowd} />
        {!isPhysical && <RadioScale label="Seating availability:" leftLabel="None" rightLabel="Plenty" value={seating} onChange={setSeating} />}
        {!isPhysical && <RadioScale label="Wi-Fi quality:" leftLabel="None" rightLabel="Excellent" value={wifi} onChange={setWifi} />}
        <div style={{ marginBottom: 16 }}>
          <label style={{ fontSize: 16, fontWeight: 700, color: C.dark, display: "block", marginBottom: 10, fontFamily: FNT }}>Tags:</label>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
            {availTags.map(t => { const on = selTags.has(t); return <button key={t} onClick={() => tagToggle(t)} style={{ padding: "7px 14px", borderRadius: 16, border: `1.5px solid ${on ? C.salmon : C.grayLighter}`, background: on ? C.salmonLight : "transparent", color: C.dark, fontSize: 12, fontFamily: FNT, cursor: "pointer", transition: "all 0.15s" }}>{t}</button>; })}
          </div>
        </div>
        <div style={{ marginBottom: 20 }}>
          <label style={{ fontSize: 16, fontWeight: 700, color: C.dark, display: "block", marginBottom: 10, fontFamily: FNT }}>Additional Comments:</label>
          <textarea value={text} onChange={e => setText(e.target.value)} placeholder="Share anything~" rows={4} style={{ width: "100%", padding: "14px 16px", borderRadius: 14, border: `1.5px solid ${C.olive}`, fontSize: 14, outline: "none", resize: "none", boxSizing: "border-box", fontFamily: FNT, background: C.bg }} />
        </div>
        {rating === 0 && noise === 0 && crowd === 0 && selTags.size === 0 && !text.trim() && <p style={{ fontSize: 12, color: C.salmon, textAlign: "center", marginBottom: 10, fontFamily: FNT }}>Please add a rating, fill a scale, select a tag, or write a comment to submit.</p>}
        <div style={{ display: "flex", justifyContent: "center" }}>
          <OutlineBtn onClick={() => { if (rating === 0 && noise === 0 && crowd === 0 && selTags.size === 0 && !text.trim()) return; setUserReviews(prev => ({...prev, [pid]: { rating, noise, crowd, seating, wifi, text, tags: [...selTags] }})); setDone(true); }}>{existing ? "Update Review" : "Submit"}</OutlineBtn>
        </div>
      </div>
      <BottomTabs active="home" onNav={nav} />
    </div>
  );
}

