          <input value={q} onChange={e => setQ(e.target.value)} placeholder="Discover new third place" autoFocus style={{ flex: 1, border: "none", outline: "none", background: "transparent", fontSize: 14, fontFamily: FNT, color: C.dark }} />
          {q && <button onClick={() => setQ("")} style={{ background: "none", border: "none", cursor: "pointer", padding: 0, fontSize: 16, color: C.gray }}>✕</button>}
