              <div style={{ width: 48, height: 48, borderRadius: 12, background: C.oliveLight, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 700, color: C.dark, fontFamily: FNT, flexShrink: 0, overflow: "hidden" }}>{p.img ? <img src={p.img} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : initials(p.name)}</div>
