              {searchHistory.map(h => (
                <button key={h} onClick={() => setQ(h)} style={{ padding: "8px 16px", borderRadius: 20, border: `1.5px solid ${C.grayLighter}`, background: "transparent", color: C.dark, fontSize: 13, fontFamily: FNT, cursor: "pointer" }}>{h}</button>
              ))}
